// Build script for `test_fixtures`.
//
// Walks `data/<group>/<name>/` and emits one `#[test]` per fixture into
// `$OUT_DIR/generated_tests.rs`. The generated test names encode the group so
// `cargo test <group>::` can target a single category.
//
// Each generated test calls into `harness::run_<group>(name)` so the harness
// binary owns all the I/O logic; `build.rs` only owns discovery + codegen.
//
// Cargo runs `#[test]` functions in parallel by default, so generating one
// test per fixture preserves the parallelism of the existing roundtrip
// crates (each fixture writes scratch output into a unique `$OUT_DIR`
// subdirectory, so there is no contention on shared files).

use std::fmt::Write as _;
use std::path::{Path, PathBuf};

fn main() {
    println!("cargo:rerun-if-changed=data");
    println!("cargo:rerun-if-changed=build.rs");

    let data = Path::new("data");
    let mut groups: Vec<PathBuf> = read_dir_sorted(data);

    let mut out = String::new();
    out.push_str("// @generated by build.rs — do not edit by hand.\n");

    for group_dir in &groups {
        let group = group_dir.file_name().unwrap().to_string_lossy().to_string();
        let fixtures = read_dir_sorted(group_dir);
        for fixture_dir in &fixtures {
            let name = fixture_dir
                .file_name()
                .unwrap()
                .to_string_lossy()
                .to_string();
            let test_name = sanitize(&format!("{group}_{name}"));
            writeln!(
                out,
                "#[test]\nfn {test_name}() {{\n    crate::run_fixture({group:?}, {name:?});\n}}",
            )
            .unwrap();
        }
        // Touch the group dir for change tracking even when empty.
        println!("cargo:rerun-if-changed={}", group_dir.display());
    }

    // Suppress unused-variable warning when `data/` only has empty groups.
    let _ = &mut groups;

    let out_dir = std::env::var("OUT_DIR").unwrap();
    std::fs::write(Path::new(&out_dir).join("generated_tests.rs"), out).unwrap();
}

fn read_dir_sorted(path: &Path) -> Vec<PathBuf> {
    let mut entries: Vec<PathBuf> = std::fs::read_dir(path)
        .map(|it| {
            it.filter_map(|e| e.ok())
                .map(|e| e.path())
                .filter(|p| p.is_dir())
                .collect()
        })
        .unwrap_or_default();
    entries.sort();
    entries
}

fn sanitize(s: &str) -> String {
    s.chars()
        .map(|c| if c.is_ascii_alphanumeric() { c } else { '_' })
        .collect()
}
